import{_ as a,o as l,c as o,ag as e}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1996年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1996年/核心总结.md","filePath":"01_letters/1996年/核心总结.md"}'),r={name:"01_letters/1996年/核心总结.md"};function i(h,t,d,n,u,s){return l(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="_1996年巴菲特致股东信核心要点" tabindex="-1">1996年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1996年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1996年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长36.1%（62亿美元）</li><li>每股账面价值增长31.8%</li><li>32年复合增长率：23.8%</li><li>股价表现落后于内在价值增长</li></ul><hr><h2 id="_1996年两大收购" tabindex="-1">1996年两大收购 <a class="header-anchor" href="#_1996年两大收购" aria-label="Permalink to &quot;1996年两大收购&quot;">​</a></h2><h3 id="_1-堪萨斯银行担保公司-kbs" tabindex="-1">1. 堪萨斯银行担保公司（KBS） <a class="header-anchor" href="#_1-堪萨斯银行担保公司-kbs" aria-label="Permalink to &quot;1. 堪萨斯银行担保公司（KBS）&quot;">​</a></h3><ul><li><strong>价格</strong>：7500万美元</li><li><strong>CEO</strong>：Don Towle</li><li><strong>特点</strong>：小型专业保险公司</li></ul><h3 id="_2-flightsafety国际" tabindex="-1">2. FlightSafety国际 <a class="header-anchor" href="#_2-flightsafety国际" aria-label="Permalink to &quot;2. FlightSafety国际&quot;">​</a></h3><ul><li><strong>价格</strong>：约15亿美元</li><li><strong>CEO</strong>：Al Ueltschi（79岁）</li><li><strong>业务</strong>：飞行员培训、模拟器</li><li><strong>运营地点</strong>：41个地点，175台模拟器</li></ul><hr><h2 id="内在价值-vs-市场价值" tabindex="-1">内在价值 vs 市场价值 <a class="header-anchor" href="#内在价值-vs-市场价值" aria-label="Permalink to &quot;内在价值 vs 市场价值&quot;">​</a></h2><h3 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h3><ul><li>1995年：股价涨幅超过内在价值</li><li>1996年：内在价值大增，股价持平</li><li><strong>结论</strong>：市场价格更接近内在价值</li></ul><blockquote><p>&quot;股票暂时超越或落后于业务，少数卖家或买家会获得超额收益，损害交易对手。&quot;</p></blockquote><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金数据-1996" tabindex="-1">浮存金数据（1996） <a class="header-anchor" href="#浮存金数据-1996" aria-label="Permalink to &quot;浮存金数据（1996）&quot;">​</a></h3><ul><li>浮存金：$6,702M（创纪录）</li><li>成本：<strong>负</strong>（盈利）</li><li>1967-1996年：30年中有22年成本为负</li></ul><h3 id="geico表现" tabindex="-1">GEICO表现 <a class="header-anchor" href="#geico表现" aria-label="Permalink to &quot;GEICO表现&quot;">​</a></h3><ul><li>自愿汽车保单增长10%（历史最佳）</li><li>承保利润目标达成</li><li>成本优势护城河持续扩大</li><li>Tony Nicely的激励机制非常有效</li></ul><h3 id="超级巨灾保险" tabindex="-1">超级巨灾保险 <a class="header-anchor" href="#超级巨灾保险" aria-label="Permalink to &quot;超级巨灾保险&quot;">​</a></h3><ul><li>1996年表现优异</li><li>最大风险：加州地震</li><li>&quot;最坏情况&quot;损失：$600M</li></ul><hr><h2 id="普通股持仓-1996年底" tabindex="-1">普通股持仓（1996年底） <a class="header-anchor" href="#普通股持仓-1996年底" aria-label="Permalink to &quot;普通股持仓（1996年底）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>市值</th></tr></thead><tbody><tr><td>可口可乐</td><td>200M股</td><td>$10,525M</td></tr><tr><td>吉列</td><td>48M股</td><td>$3,732M</td></tr><tr><td>美国运通</td><td>49.5M股</td><td>$2,794M</td></tr><tr><td>房地美</td><td>64.2M股</td><td>$1,773M</td></tr><tr><td>富国银行</td><td>7.29M股</td><td>$1,967M</td></tr><tr><td>迪士尼</td><td>24.6M股</td><td>$1,717M</td></tr><tr><td>麦当劳</td><td>30.2M股</td><td>$1,368M</td></tr></tbody></table><hr><h2 id="必然企业-概念" tabindex="-1">&quot;必然企业&quot;概念 <a class="header-anchor" href="#必然企业-概念" aria-label="Permalink to &quot;&quot;必然企业&quot;概念&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><ul><li>10年、20年后仍将主导其领域的企业</li><li>几乎确定拥有巨大竞争优势</li></ul><h3 id="例子" tabindex="-1">例子 <a class="header-anchor" href="#例子" aria-label="Permalink to &quot;例子&quot;">​</a></h3><ul><li>可口可乐</li><li>吉列</li></ul><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><blockquote><p>&quot;没有人——即使是激烈竞争的诚实评估者——会质疑可口可乐和吉列将在投资生涯中主导其领域。&quot;</p></blockquote><h3 id="警告" tabindex="-1">警告 <a class="header-anchor" href="#警告" aria-label="Permalink to &quot;警告&quot;">​</a></h3><blockquote><p>&quot;为即使是最好的企业支付过高的价格也是一种风险。&quot;</p></blockquote><hr><h2 id="投资原则" tabindex="-1">投资原则 <a class="header-anchor" href="#投资原则" aria-label="Permalink to &quot;投资原则&quot;">​</a></h2><h3 id="能力圈" tabindex="-1">能力圈 <a class="header-anchor" href="#能力圈" aria-label="Permalink to &quot;能力圈&quot;">​</a></h3><blockquote><p>&quot;投资者不需要了解每家公司，只需要评估其能力圈内的公司。能力圈的大小不重要；知道其边界才是关键的。&quot;</p></blockquote><h3 id="集中投资" tabindex="-1">集中投资 <a class="header-anchor" href="#集中投资" aria-label="Permalink to &quot;集中投资&quot;">​</a></h3><blockquote><p>&quot;迈克尔·乔丹得分占球队的很大比例，你会因为他在球队中如此重要而交易他吗？&quot;</p></blockquote><h3 id="不需要什么" tabindex="-1">不需要什么 <a class="header-anchor" href="#不需要什么" aria-label="Permalink to &quot;不需要什么&quot;">​</a></h3><blockquote><p>&quot;成功投资不需要理解贝塔、有效市场、现代投资组合理论、期权定价或新兴市场。&quot;</p></blockquote><hr><h2 id="税务贡献" tabindex="-1">税务贡献 <a class="header-anchor" href="#税务贡献" aria-label="Permalink to &quot;税务贡献&quot;">​</a></h2><ul><li>1996年缴税：8.6亿美元</li><li>如果2000个其他纳税人支付相同金额，政府将实现预算平衡</li></ul><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于集中投资</strong>：</p><blockquote><p>&quot;我们继续通过打盹比通过活动赚更多钱。&quot;</p></blockquote></li><li><p><strong>关于变化</strong>：</p><blockquote><p>&quot;作为投资者，我们对发酵行业的反应就像我们对太空探索的态度：我们赞扬这一努力，但宁愿跳过 ride。&quot;</p></blockquote></li><li><p><strong>关于能力圈</strong>：</p><blockquote><p>&quot;你只需要能够正确评估选定企业。&quot;</p></blockquote></li><li><p><strong>关于长期持有</strong>：</p><blockquote><p>&quot;如果你不愿意持有股票10年，那就不要考虑持有10分钟。&quot;</p></blockquote></li></ol><hr><h2 id="_1996年启示" tabindex="-1">1996年启示 <a class="header-anchor" href="#_1996年启示" aria-label="Permalink to &quot;1996年启示&quot;">​</a></h2><ol><li><strong>内在价值终将体现</strong>：短期市场波动不影响长期价值</li><li><strong>规模与优势</strong>：大资金也能找到好机会</li><li><strong>优秀管理层稀缺</strong>：找到就要珍惜</li><li><strong>不预测市场</strong>：专注于企业价值</li><li><strong>耐心等待</strong>：好机会值得等待</li></ol>',52)])])}const b=a(r,[["render",i]]);export{c as __pageData,b as default};
